import React from 'react';

interface ControlledInputProps {
  value: string;
  onChange: (newValue: string) => void;
}

function ControlledInput({ value, onChange }: ControlledInputProps): JSX.Element {
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    // Filter out non-alphanumeric characters (except spaces)
    const filtered = newValue.replace(/[^a-zA-Z0-9 ]/g, '');
    onChange(filtered);
  };

  const handleClear = () => {
    onChange('');
  };

  return (
    <div>
      <input
        type="text"
        value={value}
        onChange={handleInputChange}
        placeholder="Enter text (alphanumeric only)"
      />
      <button onClick={handleClear}>Clear</button>
    </div>
  );
}

export default ControlledInput;

