import React, { useReducer, useState } from 'react';

function useFormInput(initialValue: string = ''): {
  value: string;
  setValue: (value: string) => void;
  reset: () => void;
} {
  const [value, setValue] = useState(initialValue);
  const reset = () => setValue(initialValue);
  return { value, setValue, reset };
}

function ToggleButton({
  isActive,
  onToggle,
}: {
  isActive: boolean;
  onToggle: () => void;
}): JSX.Element {
  return (
    <button
      onClick={onToggle}
      style={{
        backgroundColor: isActive ? 'green' : 'red',
        color: 'white',
        padding: '8px 16px',
        border: 'none',
        borderRadius: '4px',
        cursor: 'pointer',
      }}
    >
      {isActive ? 'Enabled' : 'Disabled'}
    </button>
  );
}

function Counter(): JSX.Element {
  type Action = { type: 'INCREMENT' } | { type: 'DECREMENT' } | { type: 'RESET' };
  const [count, dispatch] = useReducer(
    (state: number, action: Action): number => {
      switch (action.type) {
        case 'INCREMENT':
          return state + 1;
        case 'DECREMENT':
          return Math.max(0, state - 1);
        case 'RESET':
          return 0;
        default:
          return state;
      }
    },
    0
  );

  return {
    count,
    dispatch,
  } as any;
}

function FormComponent(): JSX.Element {
  const { value: name, setValue: setName, reset: resetName } = useFormInput('');
  const [isActive, setIsActive] = useState(false);
  const { count, dispatch } = Counter();
  const [lastSubmitted, setLastSubmitted] = useState('');

  const handleSubmit = () => {
    if (isActive && name.trim()) {
      setLastSubmitted(name);
      dispatch({ type: 'INCREMENT' });
      resetName();
    }
  };

  const handleReset = () => {
    resetName();
    dispatch({ type: 'RESET' });
    setLastSubmitted('');
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h2>Form Component</h2>
      <div style={{ marginBottom: '10px' }}>
        <label>
          Name:{' '}
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Enter your name"
            style={{ padding: '8px', marginLeft: '8px' }}
          />
        </label>
      </div>
      <div style={{ marginBottom: '10px' }}>
        <label style={{ marginRight: '10px' }}>Enable Submission:</label>
        <ToggleButton
          isActive={isActive}
          onToggle={() => setIsActive(!isActive)}
        />
      </div>
      <div style={{ marginBottom: '10px' }}>
        <button
          onClick={handleSubmit}
          disabled={!isActive || !name.trim()}
          style={{
            padding: '8px 16px',
            marginRight: '8px',
            cursor: !isActive || !name.trim() ? 'not-allowed' : 'pointer',
            backgroundColor: !isActive || !name.trim() ? '#ccc' : '#007bff',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
          }}
        >
          Submit
        </button>
        <button
          onClick={handleReset}
          style={{
            padding: '8px 16px',
            cursor: 'pointer',
            backgroundColor: '#6c757d',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
          }}
        >
          Reset All
        </button>
      </div>
      <div style={{ marginTop: '20px', padding: '10px', backgroundColor: '#f0f0f0' }}>
        <p>Total Submissions: {count}</p>
        {lastSubmitted && <p>Last Submitted: {lastSubmitted}</p>}
      </div>
    </div>
  );
}

export default FormComponent;

