import React, { useState, useCallback } from 'react';

interface ValidationRule {
  type: 'required' | 'email' | 'minLength' | 'maxLength' | 'pattern' | 'custom';
  message: string;
  value?: number | RegExp;
  validator?: (value: any) => boolean;
}

interface FormState {
  values: Record<string, any>;
  errors: Record<string, string[]>;
  touched: Record<string, boolean>;
  dirty: Record<string, boolean>;
}

interface UseFormOptions {
  initialValues: Record<string, any>;
  onSubmit: (values: Record<string, any>) => void | Promise<void>;
}

function useForm(options: UseFormOptions) {
  const [formState, setFormState] = useState<FormState>({
    values: options.initialValues,
    errors: {},
    touched: {},
    dirty: {}
  });

  const validationRules = React.useRef<Record<string, ValidationRule[]>>({});

  const validateField = useCallback((fieldName: string, value: any): string[] => {
    const rules = validationRules.current[fieldName] || [];
    const errors: string[] = [];

    for (const rule of rules) {
      let isValid = true;

      switch (rule.type) {
        case 'required':
          isValid = value !== '' && value !== null && value !== undefined;
          break;
        case 'email':
          isValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
          break;
        case 'minLength':
          isValid = String(value).length >= (rule.value as number);
          break;
        case 'maxLength':
          isValid = String(value).length <= (rule.value as number);
          break;
        case 'pattern':
          isValid = (rule.value as RegExp).test(value);
          break;
        case 'custom':
          isValid = rule.validator?.(value) ?? true;
          break;
      }

      if (!isValid) {
        errors.push(rule.message);
      }
    }

    return errors;
  }, []);

  const registerField = useCallback((fieldName: string, rules: ValidationRule[]) => {
    validationRules.current[fieldName] = rules;
    const initialErrors = validateField(fieldName, formState.values[fieldName]);
    setFormState(prev => ({
      ...prev,
      errors: { ...prev.errors, [fieldName]: initialErrors }
    }));
  }, [validateField, formState.values]);

  const validate = useCallback(() => {
    const newErrors: Record<string, string[]> = {};
    let isValid = true;

    for (const fieldName in validationRules.current) {
      const errors = validateField(fieldName, formState.values[fieldName]);
      if (errors.length > 0) {
        isValid = false;
        newErrors[fieldName] = errors;
      }
    }

    setFormState(prev => ({
      ...prev,
      errors: newErrors
    }));

    return { isValid, errors: newErrors, values: formState.values };
  }, [validateField, formState.values]);

  const handleChange = useCallback((fieldName: string, value: any) => {
    setFormState(prev => {
      const errors = validateField(fieldName, value);
      return {
        ...prev,
        values: { ...prev.values, [fieldName]: value },
        errors: { ...prev.errors, [fieldName]: errors },
        dirty: { ...prev.dirty, [fieldName]: true }
      };
    });
  }, [validateField]);

  const handleBlur = useCallback((fieldName: string) => {
    setFormState(prev => ({
      ...prev,
      touched: { ...prev.touched, [fieldName]: true }
    }));
  }, []);

  const handleSubmit = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    const { isValid, values } = validate();
    if (isValid) {
      await options.onSubmit(values);
    }
  }, [validate, options.onSubmit]);

  return {
    formState,
    registerField,
    validate,
    handleChange,
    handleBlur,
    handleSubmit
  };
}

